        domain = domain.trim();
        if (domain.endsWith(".")) {
            domain = domain.substring(0, domain.length() - 1);
        }
        domain = IDN.toASCII(domain);
        if (typoDomains.containsKey(domain)) {
            domain = typoDomains.get(domain);
